"""
MKT Christ Commentary — 1 Kings chapters 15–17 (fill)
Run: python3 scripts/zc-christ-1kings-15-17-fill.py

Covers 89 missing verses:
  ch15: 33 missing (v5 already exists)
  ch16: 34 missing (chapter fully empty)
  ch17: 22 missing (v6 and v22 already exist)

Key decisions:
- nîr (lamp) promise treated as direct Davidic-messianic trajectory
- Zarephath widow episode classified as explicit type (Luke 4:25-26 makes it so)
- Elijah's ministry overall classified as shadow/type of John the Baptist and
  prophetic office leading to Christ; the resurrection of the widow's son is a
  direct type of resurrection
- Hiel's Jericho rebuilding (16:34) treated as curse-fulfillment pointing to
  Christ's absorption of the curse (Gal 3:13)
- All 34 ch16 verses need entries; most use 'revelation of God' or 'theme'
  since the chapter is primarily political narrative (Omri/Ahab)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS1 = {
  "15": {
    "1": '<p>A theme: Abijam son of Rehoboam begins a three-year reign that is evaluated as failing — he walked in all the sins of his father. The Davidic dynasty continues not because of Abijam\'s merit but because YHWH had promised David a lamp (<em>nîr</em>) in Jerusalem. This verse opens a demonstration of the principle the NT will call grace: the covenant is preserved through faithless kings for the sake of the one faithful Son who will come.</p>',
    "2": '<p>A theme: Maacah daughter of Abishalom as queen mother positions the Absalom rebellion\'s lineage inside the continuing Davidic court. The Davidic line\'s resilience through moral failure and family dysfunction demonstrates the covenant\'s unconditional character — the promise given to David does not depend on the personal holiness of any successor. This is the logic Paul develops in Romans 9–11: covenant faithfulness belongs to God, not to bloodline performance.</p>',
    "3": '<p>A revelation of God: Abijam\'s heart was not fully devoted to YHWH as his ancestor David\'s was. The Deuteronomistic criterion of wholeness of heart (<em>šālēm</em>) points toward the NT\'s demand for an undivided heart (Matt 22:37) and the new covenant promise of a new heart (Ezek 36:26). No Davidic king fully met the <em>šālēm</em> standard; only Christ, who loved God with his entire being, fulfills what the criterion demands.</p>',
    "4": '<p>A direct allusion: for David\'s sake, YHWH gave him a lamp in Jerusalem — <em>nîr</em>, a dynasty-pledge. The lamp metaphor for the continuing Davidic line (also 11:36; 2 Kgs 8:19) culminates in Zechariah\'s Benedictus (Luke 1:78–79): \'the dawn from on high will visit us,\' echoing the lamp imagery. Christ is the lamp that cannot be extinguished — the fulfillment of the <em>nîr</em> promise that YHWH made to David and upheld through every unworthy successor.</p>',
    "6": '<p>A theme: the perpetual war between Rehoboam and Jeroboam continued throughout Abijam\'s life. The divided kingdom\'s internal warfare — Judah vs. Israel — is the ongoing consequence of Solomon\'s apostasy and Rehoboam\'s folly. The NT\'s vision of reconciliation (Eph 2:14–16, \'the dividing wall of hostility\') and the restoration of the unified people of God under one King (Ezek 37:15–28) provides the eschatological resolution to the division this verse perpetuates.</p>',
    "7": '<p>A theme: the archival reference to the Book of the Chronicles of the Kings of Judah is a reminder that historical accountability continues. Every king\'s acts are recorded — this anticipates the NT teaching that every deed will be disclosed at judgment (2 Cor 5:10; Rev 20:12). The partial, human record of the court chronicles points toward the complete, divine account before which all history stands.</p>',
    "8": '<p>A theme: Abijam rested with his ancestors and was buried in the city of David — the royal burial formula confirms his place in the Davidic line even in moral failure. The contrast the NT makes explicit: Christ is the one descendant of David who did not merely \'rest with his ancestors\' but was raised from the dead (Acts 13:34–37, quoting Ps 16:10: \'you will not let your Holy One see decay\').</p>',
    "9": '<p>A theme: Asa\'s accession is set in the synchronistic chronology of the two kingdoms. The faithfulness of his reign will be a rare bright point — the Deuteronomistic evaluation \'as David his ancestor had done\' (v.11) places him in the Davidic standard. Asa\'s reign demonstrates that covenant renewal is possible even within the compromised Davidic line, anticipating the ultimate covenant renewal in Christ.</p>',
    "10": '<p>A theme: Maacah daughter of Abishalom appears again as the dominant female figure across two reigns, holding the queen-mother (<em>gᵉḇîrāh</em>) position. The queen-mother institution in Judah had significant power — the removal of Maacah (v.13) for Asherah idolatry shows that no family loyalty overrides covenant fidelity. This anticipates the radical demand of Christ (Matt 10:37: \'whoever loves father or mother more than me is not worthy of me\').</p>',
    "11": '<p>A theme: Asa did what was right in YHWH\'s eyes, as David his ancestor had done. The Davidic standard becomes the criterion for all subsequent Judean kingship. Only Christ ultimately fulfills this criterion without qualification — \'this is my beloved Son, in whom I am well pleased\' (Matt 3:17) is the divine evaluation that Asa approximated but no Davidic king fully received.</p>',
    "12": '<p>A shadow: Asa expelled the cult devotees (<em>qᵉdēšîm</em>) and removed the idols. This cultic purification — the casting out of what defiles the covenant people — anticipates the temple cleansing by Christ (John 2:13–17), the ultimate purification of God\'s house. Christ\'s purging of the temple enacts with finality what Asa\'s reform could only accomplish temporarily.</p>',
    "13": '<p>A shadow: Asa removed his grandmother Maacah from the queen-mother position for making an abominable image for Asherah. The deposition of the queen mother for idolatry, and the burning of her idol at the Kidron Valley, models the NT\'s teaching that no human authority — even the highest-ranking family member — stands above the claim of God. The Kidron Valley becomes in John 18:1 the place where Jesus crosses on his way to betrayal and death, the ultimate \'crossing\' that purges all remaining idolatry.</p>',
    "14": '<p>A theme: the high places were not removed, yet Asa\'s heart was fully devoted to YHWH all his days. The honest qualification — reform was real but incomplete — is the condition of every faithful person before the final eschatological purification. Christ\'s kingdom alone removes all high places permanently (Rev 21:22: \'the city has no need of a temple\').</p>',
    "15": '<p>A theme: Asa brought his father\'s and his own dedicated gifts into the house of YHWH. The temple as the repository of dedicated things prefigures the NT\'s teaching that all things offered to God are received — Christ is the one through whom every gift passes to the Father (Heb 13:15–16: \'through him, then, let us continually offer a sacrifice of praise\').</p>',
    "16": '<p>A theme: war between Asa and Baasha all their days. The perpetual border conflict between the two kingdoms continues the division of v.6. The shalom of the kingdom of God — where there is no more war between the tribes of God\'s people — belongs to the eschatological age inaugurated by Christ (Isa 9:6–7; Eph 2:14–15).</p>',
    "17": '<p>A shadow: Baasha fortified Ramah to blockade Judah — the enemy building a wall against God\'s people. The NT reverse pattern: Christ tears down the dividing wall between peoples (Eph 2:14), while Baasha represents the human instinct to build division. Ramah is also the city of Rachel\'s weeping (Jer 31:15; Matt 2:18) — the site of lament over Israel\'s exile that Matthew connects to the massacre of the innocents under Herod.</p>',
    "18": '<p>A theme: Asa emptied the temple treasury to purchase Ben-hadad\'s military alliance — a pragmatic compromise of the sacred for political survival. This pattern of drawing on what belongs to God for human security purposes is precisely what the NT warns against: trusting in human alliances rather than divine provision. Christ does not negotiate political treaties; his kingdom comes through weakness and cross, not through treasury-backed diplomacy.</p>',
    "19": '<p>A theme: the covenant language of the Ben-hadad treaty (<em>bᵉrît</em>) — \'a covenant between me and you\' — is deliberately covenantal vocabulary applied to a pagan military pact. The misuse of covenant categories for human political purposes is corrected in the NT: the covenant is between God and humanity through Christ\'s blood (Luke 22:20: \'this cup is the new covenant in my blood\'), not between competing kings.</p>',
    "20": '<p>A revelation of God: Ben-hadad\'s military campaign into the northern kingdom at Asa\'s request demonstrates that YHWH can use pagan powers as instruments of his purposes — a theology the Prophets will develop fully (Isa 10:5–7: Assyria as the rod of YHWH\'s anger). Paul makes this universal: \'all governing authorities have been established by God\' (Rom 13:1). Christ as Lord of all nations is the fulfillment of this sovereignty.</p>',
    "21": '<p>A theme: Baasha abandoned the Ramah fortification when Aram attacked from the north. The rapid reversal — military plans collapsed by an unexpected geopolitical shift — demonstrates the fragility of human strategic planning. James 4:13–15 draws on this pattern: do not boast about tomorrow\'s plans, for life is a mist. Christ\'s kingdom, by contrast, cannot be shaken (Heb 12:28).</p>',
    "22": '<p>A theme: Asa conscripted all Judah with no exemption to carry away Baasha\'s Ramah material and build Geba and Mizpah. The forced labor levy (<em>mas</em>) echoes Solomon\'s corvée (ch.5, 9) — the burden of human political construction projects. Christ calls his followers to a different labor: his yoke is easy and his burden is light (Matt 11:30), the antithesis of the forced labor that characterizes every human kingdom.</p>',
    "23": '<p>A theme: Asa\'s later illness and its narrative placement — even a faithful king suffers bodily decline. The detail that in old age he was diseased in his feet connects the righteous king to physical mortality. Christ\'s resurrection is the answer to this universal trajectory: the faithful are not exempt from bodily weakness in this age, but the resurrection reverses it permanently (1 Cor 15:42–44).</p>',
    "24": '<p>A theme: Asa rested with his ancestors and was buried in the city of David. The burial formula for the faithful king marks his death as expected and dignified — yet still death. The contrast with Christ is the NT\'s central claim: \'he is not here, he has risen\' (Luke 24:6). The city of David is where Christ was born (Luke 2:11) and where the resurrection happens, transforming the burial city into the resurrection city.</p>',
    "25": '<p>A theme: Nadab son of Jeroboam\'s two-year reign initiates the cycle of northern dynastic violence. The brevity and violence of the northern monarchies stands against the Davidic covenant\'s promised permanence — the contrast points toward the one King whose throne endures (Ps 89:29; Heb 1:8: \'your throne, O God, is forever\').</p>',
    "26": '<p>A theme: Nadab walked in the way of his father and in Jeroboam\'s sin. The inherited pattern of sin — transmitted from father to son — is the condition of all humanity under Adam. Christ breaks this pattern: he does not inherit ancestral sin but becomes the new Adam from whom a new humanity descends (Rom 5:12–19; 1 Cor 15:45–49). Where Jeroboam\'s sin propagates through his dynasty, Christ\'s righteousness is imputed to all who are united to him.</p>',
    "27": '<p>A revelation of God: Baasha conspired against Nadab at Gibbethon during a military siege — the political world\'s instability revealed. Conspiracy, betrayal, and assassination characterize every human political order. Christ enters this world of violent politics as the one who is conspired against (Matt 26:3–4: \'the chief priests and elders of the people gathered in the palace of the high priest and conspired to arrest Jesus\') — yet his betrayal accomplishes redemption rather than mere regime change.</p>',
    "28": '<p>A theme: Baasha killed Nadab in Asa\'s third year and reigned in his place. The succession of coups demonstrates that no northern king achieved the security of the Davidic covenant. The contrast with the messianic king is Psalm 2\'s declaration: despite the conspiracy of kings and rulers, YHWH\'s anointed is set on Zion, and the nations are his inheritance.</p>',
    "29": '<p>A theme: Baasha struck down the entire house of Jeroboam, leaving not one soul alive. The total elimination of a royal dynasty was YHWH\'s prophetic judgment (14:14) on Jeroboam\'s covenant violation — yet the instrument of judgment (Baasha) is himself guilty. This pattern of imperfect human judges executing divine verdicts points toward the one righteous judge (Acts 17:31): Christ, who executes final judgment without himself becoming guilty.</p>',
    "30": '<p>A revelation of God: the theological explanation for Jeroboam\'s dynasty\'s elimination — the sins of Jeroboam and the sins he caused Israel to commit, provoking YHWH to anger. The double accountability (personal sin and corporate causation) is the pattern that the NT traces in Adam: one man\'s sin spread to all (Rom 5:12). Christ reverses this: one man\'s obedience brings justification for all (Rom 5:18–19).</p>',
    "31": '<p>A theme: the archival closing formula for Nadab confirms that even short, violent reigns are held accountable. The phrase \'chronicles of the kings of Israel\' is itself an assertion that history is not random — there is a record, and the record will be reviewed. The book of life (Rev 20:12, 15) is the eschatological form of this accountability, and Christ is the one who opens it (Rev 5:5).</p>',
    "32": '<p>A theme: resumptive war notice between Asa and Baasha. The unresolved conflict between the divided kingdoms is part of the \'already\' of the fallen order; the peace of God\'s kingdom is the \'not yet.\' The NT\'s use of shalom — \'peace with God through our Lord Jesus Christ\' (Rom 5:1) — is the beginning of the eschatological resolution of all such conflict.</p>',
    "33": '<p>A theme: Baasha reigned at Tirzah twenty-four years — the longest northern reign after Jeroboam. Length of reign brings no inherent blessing in the northern kingdom; what matters is covenant faithfulness. Christ\'s reign is eternal (Heb 1:8: \'your throne, O God, is forever and ever\'), but its distinguishing mark is not duration alone — it is the righteousness of the ruler (Heb 1:9).</p>',
    "34": '<p>A theme: Baasha walked in the way of Jeroboam — the theological verdict applied to the instrument of Jeroboam\'s judgment. The irony of the judge becoming the next judged object illustrates the universality of human sin: no human judge is righteous enough to escape the verdict he pronounces on others (Rom 2:1: \'you have no excuse, whoever you are, when you judge another\'). Only Christ, who bore the judgment without having earned it, escapes this irony.</p>'
  },
  "16": {
    "1": '<p>A revelation of God: the word of YHWH came to Jehu son of Hanani against Baasha. The prophetic oracle against a king demonstrates YHWH\'s sovereignty over human political power — no dynasty exists outside divine scrutiny. Christ is both the fulfillment of the prophetic office (Heb 1:1–2: \'in these last days God has spoken to us by his Son\') and the ultimate object of all prophetic witness (Luke 24:44; John 5:39).</p>',
    "2": '<p>A revelation of God: YHWH elevated Baasha from the dust to be ruler over Israel. The elevation-from-nothing formula reveals the pattern of divine patronage: YHWH alone is the source of human authority. This is the theology Paul expresses in Rom 13:1 (\'there is no authority except from God\') and that Christ demonstrates when he says to Pilate, \'you would have no authority over me at all unless it had been given you from above\' (John 19:11).</p>',
    "3": '<p>A revelation of God: the consuming judgment of Baasha\'s house — the same formula applied to Jeroboam (14:10) and later to Ahab (21:21). The repeated application of identical judgment patterns to successive apostate dynasties reveals the consistency of YHWH\'s character: he does not change his moral standard to accommodate political power. Christ\'s proclamation that \'every plant that my heavenly Father has not planted will be rooted up\' (Matt 15:13) belongs to this same theological tradition.</p>',
    "4": '<p>A theme: the curse of non-burial — dogs and birds consuming the dead — represents the ultimate social dishonor. The NT revaluation: Christ was given a proper burial by Joseph of Arimathea (Matt 27:57–60), but more significantly, he passed through the full experience of human death and burial so that his resurrection could be bodily and verifiable. The burial rites of the ancient world witness to the seriousness of death; Christ\'s resurrection witnesses to its conquest.</p>',
    "5": '<p>A theme: Baasha\'s might and acts recorded in the chronicles of the kings of Israel. The achievement and power of earthly kings is historically documented but temporally bounded. Christ alone is \'the same yesterday, today, and forever\' (Heb 13:8); all other political power passes.</p>',
    "6": '<p>A theme: Baasha rested with his ancestors and was buried at Tirzah, his son Elah reigning in his place. The peaceful burial despite the prophetic doom on his dynasty — Baasha himself does not see the consequences of his apostasy in his lifetime — is a demonstration of the delayed character of divine judgment. 2 Pet 3:9 addresses this: YHWH is patient, not wishing that any should perish. The judgment announced comes precisely, but in YHWH\'s time, not the observer\'s.</p>',
    "7": '<p>A revelation of God: the prophetic confirmation that YHWH\'s word through Jehu came against Baasha \'because of all the evil he did.\' The \'because\' (the moral causation behind historical events) is YHWH\'s characteristic mode of explaining history. Christ embodies this same moral transparency: at his judgment seat, the reasons for all verdicts will be disclosed (2 Cor 5:10: \'so that each one may receive what is due for what he has done in the body\').</p>',
    "8": '<p>A theme: Elah son of Baasha reigned two years. The brevity of this reign — again a royal tenancy lasting only long enough to fulfill a prophetic word — continues the pattern of northern instability. The contrast: Christ\'s reign has no end (Luke 1:33: \'and of his kingdom there will be no end\').</p>',
    "9": '<p>A revelation of God: Zimri\'s conspiracy against the drunken Elah reveals the vulnerability of every human dynasty — it can be ended by one man with one sword while the king is incapacitated. The NT\'s stark contrast: \'neither death, nor life, nor angels, nor rulers... will be able to separate us from the love of God in Christ Jesus\' (Rom 8:38–39). No conspiracy can end what Christ rules.</p>',
    "10": '<p>A theme: Zimri killed Elah and reigned in his place in the twenty-seventh year of Asa. The synchronistic dating continues to locate northern chaos against the relatively stable Judean background — a structural device that keeps the Davidic covenant\'s endurance in view even during the northern kingdom\'s convulsions.</p>',
    "11": '<p>A theme: Zimri struck down the entire house of Baasha — not one male left alive. The total male elimination (<em>maštin bᵉqîr</em>) echoes Jeroboam\'s dynasty\'s end (15:29). These repeated total eliminations demonstrate that human dynasties, unlike the divine covenant, have no guaranteed succession. Christ is \'the heir of all things\' (Heb 1:2) — the one in whom the inheritance of the entire human family is secured, not through conquest of rivals but through faithful inheritance from the Father.</p>',
    "12": '<p>A direct fulfillment: Zimri destroyed the house of Baasha in fulfillment of the word of YHWH spoken through Jehu the prophet. The fulfillment formula (<em>kᵉḏiḇar YHWH</em>) is the characteristic marker of prophetic word coming true. Christ is the ultimate fulfillment of prophetic word (Matt 5:17: \'I have not come to abolish the Law or the Prophets, but to fulfill them\') — the one in whom every \'kᵉḏiḇar YHWH\' achieves its deepest meaning.</p>',
    "13": '<p>A theme: the theological indictment of Baasha and Elah — their sins and the vanities (<em>haḇlêhem</em>) by which they provoked YHWH. <em>Haḇlîm</em> (vapors/vanities) is Ecclesiastes\' word for the futility of human striving. Paul applies the same verdict to idolatrous Gentiles (Rom 1:21: \'they became futile in their thinking\'); the remedy is the knowledge of God in Christ (2 Cor 4:6).</p>',
    "14": '<p>A theme: the archival formula for Elah — brief reign, brief record. Every mortal king\'s record closes; Christ\'s record is written in the living and enduring word of God (1 Pet 1:23–25) and his name is written above every name (Phil 2:9–10).</p>',
    "15": '<p>A theme: Zimri reigned seven days — the shortest monarchy on record. Even within the seven-day reign, the Jeroboamic verdict applies (v.19). The theological point: no reign is too brief to escape moral accountability. Conversely, no life is too brief to be covered by Christ\'s atonement (the thief on the cross, Luke 23:40–43, demonstrates the shortest possible salvific \'reign\' — from death-bed to paradise).</p>',
    "16": '<p>A theme: the army in the field made Omri king when they heard of the coup — a military field-election that bypasses all normal succession. The scene of armies acclaiming a king at war is the background for Revelation\'s vision of the armies of heaven following the Word of God (Rev 19:14). The contrast: human generals are acclaimed by frightened, war-weary troops; Christ is acclaimed by \'a great multitude that no one could number\' (Rev 7:9) for his victory over death itself.</p>',
    "17": '<p>A theme: Omri besieged Tirzah with the army. Civil war — Israelite against Israelite — is the ultimate fruit of the northern apostasy: the covenant people consuming one another. Paul\'s warning in Gal 5:15 (\'if you bite and devour one another, watch out that you are not consumed by one another\') belongs to this tradition. Christ as the true King creates unity rather than fragmentation (John 17:21: \'that they may all be one\').</p>',
    "18": '<p>A revelation of God: Zimri burned the palace over himself when he saw defeat was certain. Self-destruction in the face of defeat — the refusal to surrender, the preference for death over capture — is the ultimate expression of pride. The NT\'s alternative: those who lose their life for Christ\'s sake will find it (Matt 16:25). Christ himself did not take his own life but gave it (John 10:18: \'no one takes it from me, but I lay it down of my own accord\').</p>',
    "19": '<p>A theme: Zimri\'s seven days received the full Jeroboamic verdict. The theological economy of the Deuteronomistic history: no one escapes evaluation, no matter how brief their influence. This anticipates the NT\'s teaching that every idle word will be accounted for (Matt 12:36) and that all works will be tested by fire (1 Cor 3:13). Christ is both the judge of all such works and the advocate who intercedes for his people (1 John 2:1).</p>',
    "20": '<p>A theme: the chronicles reference for Zimri — conspiracy as the defining act of a seven-day reign. The conspiracy to seize power is the political expression of the fundamental human sin: taking for oneself what belongs to God. Christ, who \'did not count equality with God a thing to be grasped\' (Phil 2:6), is the antithesis of every coup-maker.</p>',
    "21": '<p>A theme: Israel split in two factions over Omri and Tibni. National division at a moment of political vacuum — the absence of divinely-established kingship creating chaos. The NT\'s vision: at the name of Jesus, \'every knee will bow\' (Phil 2:10) — all factions resolved into a single confession under one Lord.</p>',
    "22": '<p>A theme: Omri\'s faction prevailed; Tibni died. Power consolidated through the death of a rival — the normal political logic of the ancient world. Christ\'s kingdom expands not through the death of rivals but through the death of the King himself, whose cross paradoxically becomes the locus of power (1 Cor 1:18: \'the word of the cross is foolishness to those who are perishing, but to us who are being saved it is the power of God\').</p>',
    "23": '<p>A theme: Omri reigned twelve years at Tirzah and then Samaria. The twelve-year reign of the founder of the most significant northern dynasty is noted in a single verse — the Deuteronomistic historian is deliberately dismissive of a king whose political achievements were extraordinary (Assyria called Israel \'the house of Omri\' for generations). The contrast: Christ\'s significance is determined not by military or administrative achievement but by who he is and what he accomplished in his atoning death.</p>',
    "24": '<p>A shadow: Omri bought the hill of Samaria and named it after the seller Shemer — founding a capital on purchased land. The purchase motif resonates with the NT\'s language of redemption: the entire earth is \'purchased\' (<em>agorazō</em>) by Christ at the cost of his blood (Rev 5:9: \'you were slain, and by your blood you ransomed people for God\'). The comparison is ironic: Omri purchased land for a capital of apostasy; Christ purchases a people for a kingdom of righteousness.</p>',
    "25": '<p>A theme: Omri did more evil than all before him — the escalating superlative in the northern monarchy\'s moral descent. The Deuteronomistic escalation (v.25, 30, 33) culminates in Ahab as the nadir, requiring the extraordinary prophetic response of Elijah. The NT recognizes that the accumulation of human sin finally required the extraordinary response of God incarnate — not a prophet but the Son himself.</p>',
    "26": '<p>A theme: Omri walked in Jeroboam\'s way, led Israel to provoke YHWH with their vanities (<em>haḇlîm</em>). The idol-as-vapor theology — idols are insubstantial — is developed in the NT\'s contrast between \'worthless things\' and the \'living God\' (Acts 14:15). Christ\'s proclamation that \'God is spirit, and those who worship him must worship in spirit and truth\' (John 4:24) is the positive fulfillment of the negative judgment on idol worship.</p>',
    "27": '<p>A theme: Omri\'s might recorded in the chronicles — but the NT\'s assessment of power reverses every such evaluation. \'God chose what is weak in the world to shame the strong\' (1 Cor 1:27). The Assyrian records of Omri\'s dynasty will outlast the biblical account of Omri himself — and both will be superseded by the only name that endures above every record (Phil 2:9).</p>',
    "28": '<p>A theme: Omri buried at Samaria — the first northern king buried in his own founded capital. The founding and burying in Samaria frames the Omride dynasty: the city is both achievement and tomb. Christ is buried in a borrowed tomb (Matt 27:60) and leaves it empty — the tomb does not define him; the resurrection does.</p>',
    "29": '<p>A shadow: Ahab son of Omri begins the reign that will receive more narrative attention than any other northern king — twenty-two years marked by Elijah\'s confrontation. Ahab\'s apostasy sets the stage for the most sustained prophetic challenge in the Books of Kings. The shadow: just as the full revelation of Israel\'s idolatry required the appearance of YHWH\'s supreme prophet (Elijah), the full revelation of human sin required the appearance of YHWH\'s supreme messenger — his own Son (Heb 1:1–2).</p>',
    "30": '<p>A theme: Ahab did more evil than all before him — the superlative that opens his reign (also v.25 for Omri, escalating). This accumulation of evil in the northern king serves a narrative and theological purpose: the greater the darkness, the more dramatic the prophetic light that answers it. John\'s Gospel opens with \'the light shines in the darkness, and the darkness has not overcome it\' (John 1:5) — the Elijah narrative in Kings is the forerunner of this larger pattern.</p>',
    "31": '<p>A shadow: Ahab married Jezebel daughter of Ethbaal and served Baal. The introduction of the false queen — the king\'s wife who leads him into idolatry — is the shadow of a deeper typological contrast. Revelation\'s \'Jezebel\' (Rev 2:20) represents the false prophetess who seduces the church; the true Bride of the Lamb (Rev 21:2) is the inverse. The faithful bride who leads toward Christ is the anti-type of Jezebel who led toward Baal.</p>',
    "32": '<p>A shadow: Ahab built a temple for Baal in Samaria. The establishment of a rival worship center to the Jerusalem temple — and specifically to YHWH\'s presence — anticipates the NT\'s confrontation between Christ (the true temple, John 2:21) and false worship. Every false temple points by contrast to the one who says \'destroy this temple, and in three days I will raise it up\' (John 2:19).</p>',
    "33": '<p>A shadow: Ahab made an Asherah pole and did more to provoke YHWH than all the kings before him. The superlative apostasy closes the narrative build-up and opens the Elijah cycle. The theological logic: the extreme of human rebellion against YHWH calls forth the extreme of YHWH\'s prophetic response. The NT\'s \'fullness of time\' (Gal 4:4) has a similar logic: when the darkness of human sin was maximally demonstrated, God sent his Son.</p>',
    "34": '<p>A direct allusion: Hiel of Bethel rebuilt Jericho, fulfilling the curse of Joshua son of Nun (Josh 6:26) at the cost of his firstborn and youngest son. The fulfillment of a centuries-old curse is a sobering testimony to the durability of divine words. The NT draws on the curse-fulfillment category in Gal 3:13: \'Christ redeemed us from the curse of the law by becoming a curse for us.\' Every unfulfilled curse in Israel\'s history is absorbed in the one who hangs on the tree (Deut 21:23), transforming divine judgment into the basis for redemption.</p>'
  },
  "17": {
    "1": '<p>A shadow: Elijah the Tishbite appears before Ahab with a drought announcement, swearing by YHWH of hosts. Jesus explicitly identifies John the Baptist as the Elijah who was to come (Matt 11:14; 17:12–13; Mark 9:11–13; Luke 1:17), and Malachi 4:5 promises an Elijah-return before the great day of YHWH. Elijah himself is thus a type of the eschatological prophet who prepares the way — as John prepared for Christ\'s first coming, and as the prophetic witness of Rev 11 prefigures the final preparation for his return.</p>',
    "2": '<p>A revelation of God: the word of YHWH comes to Elijah immediately after his bold announcement — directing him to safety. YHWH does not send his prophet into danger and abandon him; he provides both the mission and the means of survival. Christ sends out his disciples with the same assurance: \'I am with you always, to the end of the age\' (Matt 28:20). The Elijah provision pattern is the OT ground of the NT promise.</p>',
    "3": '<p>A shadow: Elijah is commanded to hide by the brook Cherith east of the Jordan — withdrawal into concealment. Jesus also withdrew to desolate places to pray (Luke 5:16; Mark 1:35) and deliberately avoided premature disclosure (Mark 1:44; John 7:4–10). The hiddenness of the prophet in dangerous times anticipates the hiddenness of the Son of Man before his appointed hour (John 7:30: \'no one laid a hand on him, because his hour had not yet come\').</p>',
    "4": '<p>A shadow: YHWH commanded the ravens (<em>ʿōrᵉḇîm</em>) to feed Elijah — unclean birds as divine provision agents. Jesus\'s teaching draws directly on this provision pattern: \'consider the ravens: they neither sow nor reap, they have neither storehouse nor barn, and yet God feeds them\' (Luke 12:24). The ravens who fed Elijah model the providential care that Christ invites his disciples to trust — care that operates outside the normal categories of clean/unclean, expected/unexpected.</p>',
    "5": '<p>A theme: Elijah\'s immediate obedience — he went and did according to the word of YHWH. The pattern of prophetic obedience to divine direction anticipates Christ\'s obedience, the ground of salvation (Rom 5:19: \'by the one man\'s obedience the many will be made righteous\'). The Elijah obedience narratives collectively are a shadow of the perfect obedience that will come.</p>',
    "7": '<p>A revelation of God: the brook dried up because there had been no rain in the land. The same divine word that announced the drought (v.1) is now experienced by the prophet — Elijah is not exempt from the physical consequences of the judgment he announced. Christ entered fully into the condition of fallen humanity: born under the law (Gal 4:4), experiencing hunger (Matt 4:2), thirst (John 19:28), and death — not as a victim of circumstance but as the one who bears the weight of the world\'s condition.</p>',
    "8": '<p>A revelation of God: the word of YHWH came to Elijah again at the moment of his need — the second commissioning follows the first provision\'s exhaustion. The pattern of divine direction that is responsive rather than exhaustive — YHWH reveals the next step when the current step is complete — is the theology of Prov 3:5–6 (\'trust in YHWH with all your heart, and do not lean on your own understanding; in all your ways acknowledge him, and he will make straight your paths\'). Christ as the Good Shepherd leads step by step (John 10:3–4).</p>',
    "9": '<p>A type: YHWH sends Elijah to Zarephath, a widow in Sidon — Phoenician territory, outside the covenant. Jesus explicitly invokes this episode in his programmatic Nazareth sermon (Luke 4:25–26): \'there were many widows in Israel in the days of Elijah... and Elijah was sent to none of them but only to Zarephath in Sidon, to a woman who was a widow.\' This is a type of the salvation extending to the Gentiles: YHWH\'s provision bypasses the expected recipients (Israel) and reaches those outside the covenant. The Gentile mission of the church is prefigured here in Elijah\'s Sidonian commission.</p>',
    "10": '<p>A type: Elijah arrived at Zarephath, found the widow at the gate gathering sticks, and asked for water. The encounter at a well or gate between a prophet/divine representative and a foreign woman is a type-scene in Scripture (cf. Gen 24, Exod 2, John 4). The Samaritan woman at the well in John 4 is the NT fulfillment of this type: a foreigner, an outsider to the covenant, who receives living water from the one greater than Elijah (John 4:12–14).</p>',
    "11": '<p>A theme: Elijah\'s escalating request — first water, then bread — tests the widow\'s hospitality. The pattern of divine request exceeding easy compliance before miracle occurs anticipates the wedding at Cana (John 2:3–5: \'they have no wine\' → \'fill the jars with water\') and the feeding of the five thousand (Matt 14:17: \'we have only five loaves\' → \'bring them here to me\'). The request that seems impossible becomes the occasion for divine provision.</p>',
    "12": '<p>A theme: the widow\'s oath \'as YHWH your God lives\' — invoking Elijah\'s God while outside the covenant herself. The Phoenician widow\'s recognition of YHWH\'s existence anticipates the Gentile recognition of the God of Israel through Christ\'s ministry: the Syrophoenician woman (Matt 15:22–28), the Roman centurion (Matt 8:5–13), and ultimately the Gentile church. YHWH\'s faithfulness extends beyond covenant borders before Christ\'s coming; in Christ it is made universal (Eph 3:6).</p>',
    "13": '<p>A type: Elijah\'s command — make me a small cake first, before you make for yourself — is a demand for priority hospitality from a starving woman. This is both a test of faith and a type of the NT demand to \'seek first the kingdom of God\' (Matt 6:33). The widow\'s compliance models the radical trust that Christ calls his disciples to: giving the first and best to God even in conditions of apparent scarcity, trusting that provision will follow.</p>',
    "14": '<p>A direct type: the oracle that the flour will not run out and the oil will not fail until YHWH sends rain is the sign of miraculous ongoing provision. Jesus draws on this typology implicitly in John 6:35 (\'I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst\'). The jar of flour and the jug of oil that are never exhausted are a type of the inexhaustible life that Christ gives — provision that does not run out because its source is YHWH himself.</p>',
    "15": '<p>A theme: the widow went and did according to Elijah\'s word — obedience preceding miracle. She and Elijah and her household ate for many days. The inclusion of \'her household\' in the blessing of obedient faith anticipates the NT pattern of household salvation: \'believe in the Lord Jesus, and you will be saved, you and your household\' (Acts 16:31). The Gentile widow\'s household, sustained by prophetic provision, is a type of the Gentile household brought into God\'s provision through Christ.</p>',
    "16": '<p>A direct type: the jar of flour was not exhausted and the jug of oil did not fail, according to the word of YHWH spoken through Elijah. The fulfillment formula marks this as a verified miracle of ongoing provision. The inexhaustible nature of the provision — sustained for months (v.15: \'many days,\' v.1: until the drought ends) — is a type of the inexhaustible nature of Christ\'s provision: the bread of life that feeds an unlimited number (John 6:11–13: twelve baskets of fragments remaining after five thousand are fed).</p>',
    "17": '<p>A shadow: after the miracle of provision, the widow\'s son fell ill and died — there was no breath (<em>nᵉšāmāh</em>) left in him. The sequence — miracle of provision, then death of the child — is the structure of divine testing that precedes a greater miracle. The pattern of \'first provided for, then tested through loss\' appears in Abraham (provision of Isaac → demand to sacrifice Isaac) and in the disciples (miraculous feeding → storm on the lake). The greater miracle always exceeds the lesser provision.</p>',
    "18": '<p>A revelation of God: the widow interprets her son\'s death as divine punishment triggered by the prophet\'s proximity — \'you came to call my sin to remembrance.\' The theological instinct — that death reveals guilt before God — is the background to Christ\'s answer when asked about the blind man in John 9:2–3 (\'Rabbi, who sinned, this man or his parents?\'). Christ corrects this simple equation while not denying the connection between sin and death: the blindness is \'so that the works of God might be displayed\' — and so with the widow\'s son.</p>',
    "19": '<p>A type: Elijah took the child from the widow\'s arms, carried him to the upper room, and laid him on his own bed. The prophet\'s intimate identification with the dead child — placing him on his own bed in the prophet\'s own private space — prefigures the NT\'s language of Christ bearing human death in his own body (1 Pet 2:24: \'he himself bore our sins in his body on the tree\'; 2 Cor 5:21: \'he made him to be sin who knew no sin\'). The prophet\'s physical embrace of the dead is a type of the incarnation\'s embrace of human mortality.</p>',
    "20": '<p>A revelation of God: Elijah\'s prayer to YHWH is a bold protest — \'have you brought evil on this widow with whom I am staying?\' The prophetic prayer that challenges divine action is a model of intimate covenant speech, not irreverent complaint. Jesus himself echoes this mode on the cross: \'my God, my God, why have you forsaken me?\' (Matt 27:46 = Ps 22:1). The cry of dereliction is the ultimate expression of the prophetic prayer that dares to address divine action directly.</p>',
    "23": '<p>A type: Elijah took the child down from the upper room and gave him to his mother. The restoration of the dead son to his grieving mother is one of the three OT resurrection types that the NT gospels echo: the widow of Zarephath here (1 Kgs 17:23), the Shunammite woman\'s son (2 Kgs 4:36–37), and the widow of Nain\'s son (Luke 7:11–17 — the closest NT parallel, with the explicit formula \'he gave him to his mother,\' Luke 7:15). Luke 7:15 quotes this verse\'s action almost verbatim, connecting Jesus\'s miracle to Elijah\'s as type to antitype.</p>',
    "24": '<p>A type: the Phoenician widow confessed, \'now I know that you are a man of God, and that the word of YHWH in your mouth is truth (<em>ʾĕmeṯ</em>).\' This is the confession that a resurrection miracle produces: death reversed confirms the prophet\'s divine commission and the reliability of YHWH\'s word. The NT\'s supreme confession follows the supreme resurrection: \'my Lord and my God\' (John 20:28, Thomas after the resurrection). The Zarephath widow\'s confession is the forerunner of the resurrection-generated faith that is the ground of Christian confession.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', '1kings')
    merge_comm(existing, KINGS1)
